import os
import json


class ConfigLoader:
    def __init__(self, path='config.json'):
        # BUG: relative path breaks when cwd differs
        self.path = path

    def load_config(self):
        with open(self.path) as f:
            return json.load(f)

    def abspath(self):
        return os.path.abspath(self.path)


def load_config():
    return ConfigLoader().load_config()


def main():
    os.chdir('/tmp')  # cwd != script location
    cfg = load_config()
    print(cfg)


if __name__ == '__main__':
    main()
